    /// Compute the 11D gravitational field — the vector from this entity to the epicenter.
    ///
    /// Each dimension: G_k = epicenter_vibrations[k] - entity_vibrations[k].
    /// The direction tells the entity which dimensions to evolve in.
    /// The magnitude tells the entity how far it is from the epicenter.
    /// When all 11 components are zero, the entity IS at the epicenter.
    pub fn gravitational_field(&self, epicenter_vibrations: &[Q; 11]) -> ([Q; 11], Q) {
        let entity_harmonics = HarmonicState::from_delta(
            &self.delta, &self.origin_delta,
            &self.trajectory, self.k_index as u64,
        );
        let field: [Q; 11] = std::array::from_fn(|k| {
            &epicenter_vibrations[k] - &entity_harmonics.vibrations[k]
        });
        // Gravitational magnitude: L1 of the 11D field vector
        let magnitude = field.iter().fold(Q::zero(), |acc, g| {
            let abs_g = (g < &Q::zero()).then(|| -g.clone()).unwrap_or(g.clone());
            acc + abs_g
        });
        (field, magnitude)
    }

